#define _USE_MATH_DEFINES
#include <iostream>
#include <cmath>
#include <limits>

class Circle {
private:
    double radius;

public:
    Circle(double r) {
        if (r < 0.0) {
            /* std::cerr << "Warning: Radius cannot be negative. Setting radius to 0." << std::endl; */
            radius = 0.0;
        } else {
            radius = r;
        }
    }
    double getRadius() const {
        return radius;
    }
    double calculateArea() const {
        return M_PI * radius * radius;
    }
};

int main() {
    std::cout.precision(std::numeric_limits<double>::max_digits10);
    double r_test;
    while (std::cin >> r_test) {
        Circle c(r_test);
        std::cout << c.calculateArea() << std::endl;
    }
    return 0;
}
